import{_ as i,I as l,o as s,c as o,j as e,a as r,J as n,ap as d}from"./chunks/framework.ockA5sXJ.js";const b=JSON.parse('{"title":"Theming","description":"Customizing the look and feel of Citizen","frontmatter":{"title":"Theming","description":"Customizing the look and feel of Citizen"},"headers":[],"relativePath":"customization/theming.md","filePath":"customization/theming.md","lastUpdated":1778562252000}'),c={name:"customization/theming.md"};function h(p,t,f,g,y,k){const a=l("CopyOrDownloadAsMarkdownButtons");return s(),o("div",null,[t[0]||(t[0]=e("div",{style:{display:"none"},hidden:"true","aria-hidden":"true"},"Are you an LLM? You can read better optimized documentation at /mediawiki-skins-Citizen/customization/theming.md for this page in Markdown format",-1)),t[1]||(t[1]=e("h1",{id:"theming",tabindex:"-1"},[r("Theming "),e("a",{class:"header-anchor",href:"#theming","aria-label":"Permalink to “Theming”"},"​")],-1)),n(a),t[2]||(t[2]=d(`<p>Citizen&#39;s visual appearance is controlled by CSS custom properties. Override them in <code>MediaWiki:Citizen.css</code> to match your wiki&#39;s brand.</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>To truly make the wiki your own, you would need CSS to style the skin and templates. If you are getting started, check out the <a href="https://river.me/blog/dev-tools" target="_blank" rel="noreferrer">How to use Dev Tools guide</a> from River!</p></div><h2 id="colors" tabindex="-1">Colors <a class="header-anchor" href="#colors" aria-label="Permalink to “Colors”">​</a></h2><h3 id="primary-color" tabindex="-1">Primary color <a class="header-anchor" href="#primary-color" aria-label="Permalink to “Primary color”">​</a></h3><p>Citizen uses the <strong>OKLCH</strong> color model for its primary color (called &quot;progressive&quot; in MediaWiki). OKLCH keeps colors perceptually consistent across light and dark mode. The default is a standard blue (<code>#36c</code>) — most wikis only need to change the hue.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Property</th><th style="text-align:left;">Description</th><th style="text-align:left;">Default value</th></tr></thead><tbody><tr><td style="text-align:left;"><code>--color-progressive-oklch__l</code></td><td style="text-align:left;">Lightness.</td><td style="text-align:left;"><code>53.25%</code></td></tr><tr><td style="text-align:left;"><code>--color-progressive-oklch__c</code></td><td style="text-align:left;">Chroma (saturation).</td><td style="text-align:left;"><code>0.1679</code></td></tr><tr><td style="text-align:left;"><code>--color-progressive-oklch__h</code></td><td style="text-align:left;">Hue — the easiest way to rebrand.</td><td style="text-align:left;"><code>262.29</code></td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">Deprecated</p><p>The HSL fallback variables are soft-deprecated and will be removed in a future version. Use the OKLCH variables above instead.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Property</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><code>--color-progressive-hsl__h</code></td><td style="text-align:left;">Hue</td></tr><tr><td style="text-align:left;"><code>--color-progressive-hsl__s</code></td><td style="text-align:left;">Saturation</td></tr><tr><td style="text-align:left;"><code>--color-progressive-hsl__l</code></td><td style="text-align:left;">Lightness</td></tr></tbody></table></div><h3 id="surface-colors" tabindex="-1">Surface colors <a class="header-anchor" href="#surface-colors" aria-label="Permalink to “Surface colors”">​</a></h3><p>Surface colors form the depth hierarchy of the UI — lower numbers sit further back.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Property</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><code>--color-surface-0</code></td><td style="text-align:left;">Page background.</td></tr><tr><td style="text-align:left;"><code>--color-surface-1</code></td><td style="text-align:left;">Cards, modals, and dropdowns.</td></tr><tr><td style="text-align:left;"><code>--color-surface-2</code></td><td style="text-align:left;">Raised elements within cards.</td></tr><tr><td style="text-align:left;"><code>--color-surface-3</code></td><td style="text-align:left;">Hover states and subtle highlights.</td></tr><tr><td style="text-align:left;"><code>--color-surface-4</code></td><td style="text-align:left;">Active states and strong highlights.</td></tr></tbody></table><h3 id="text-colors" tabindex="-1">Text colors <a class="header-anchor" href="#text-colors" aria-label="Permalink to “Text colors”">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Property</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><code>--color-base</code></td><td style="text-align:left;">Default body text.</td></tr><tr><td style="text-align:left;"><code>--color-emphasized</code></td><td style="text-align:left;">Titles and headings.</td></tr><tr><td style="text-align:left;"><code>--color-subtle</code></td><td style="text-align:left;">Captions and metadata.</td></tr><tr><td style="text-align:left;"><code>--color-link</code></td><td style="text-align:left;">Link text.</td></tr></tbody></table><h2 id="typography" tabindex="-1">Typography <a class="header-anchor" href="#typography" aria-label="Permalink to “Typography”">​</a></h2><p>Citizen ships with <a href="https://fonts.google.com/specimen/Roboto+Flex" target="_blank" rel="noreferrer">Roboto Flex</a> as its default typeface. You can swap it out by overriding the font family variables:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Property</th><th style="text-align:left;">Description</th><th style="text-align:left;">Default value</th></tr></thead><tbody><tr><td style="text-align:left;"><code>--font-family-citizen-base</code></td><td style="text-align:left;">Most text in the UI.</td><td style="text-align:left;"><code>&#39;Roboto&#39;</code></td></tr><tr><td style="text-align:left;"><code>--font-family-citizen-serif</code></td><td style="text-align:left;">Serif option in the editor and some extensions.</td><td style="text-align:left;"><code>&#39;Roboto Serif&#39;</code></td></tr><tr><td style="text-align:left;"><code>--font-family-citizen-monospace</code></td><td style="text-align:left;">Code blocks and editors.</td><td style="text-align:left;"><code>&#39;Roboto Mono&#39;</code></td></tr></tbody></table><p>To use a font from <a href="https://fonts.google.com" target="_blank" rel="noreferrer">Google Fonts</a> (or any other source), import it and set the variable in <code>MediaWiki:Citizen.css</code>. Request the full weight range so all of Citizen&#39;s weight variations work correctly:</p><div class="language-css"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">@import</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> url</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;https://fonts.googleapis.com/css2?family=Inter:wght@100..900&amp;display=swap&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">:root</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">    --font-family-citizen-base</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;Inter&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>Set just the font name. Citizen adds <code>system-ui</code>, <code>sans-serif</code>, and language-specific fallbacks downstream — putting them here yourself can short-circuit the chain for users on the CJK or Arabic modules.</p></div><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>Any font works, but <a href="https://fonts.google.com/variablefonts" target="_blank" rel="noreferrer">variable fonts</a> are recommended — Citizen uses multiple font weights, and a variable font serves them all from a single file.</p></div><h3 id="avoiding-font-flicker" tabindex="-1">Avoiding font flicker <a class="header-anchor" href="#avoiding-font-flicker" aria-label="Permalink to “Avoiding font flicker”">​</a></h3><p>Web fonts load asynchronously — until yours arrives, the browser shows a system fallback. If the two fonts have different metrics, text visibly resizes or shifts when the swap happens.</p><p>Citizen ships a metric-matched fallback for Roboto Flex that hides this. If you&#39;ve swapped Roboto for another font, you can do the same:</p><ol><li>Generate override descriptors with a tool like <a href="https://meowni.ca/font-style-matcher/" target="_blank" rel="noreferrer">font-style-matcher</a> or <a href="https://screenspan.net/fallback" target="_blank" rel="noreferrer">screenspan.net/fallback</a>.</li><li>Add the resulting <code>@font-face</code> to your CSS under a distinct family name like <code>&#39;Inter-fallback&#39;</code>.</li><li>Reference it right after your font in the variable:</li></ol><div class="language-css"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">:root</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">    --font-family-citizen-base</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;Inter&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;Inter-fallback&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h2 id="layout" tabindex="-1">Layout <a class="header-anchor" href="#layout" aria-label="Permalink to “Layout”">​</a></h2><p>The page width options are user preferences — users pick from Standard, Wide, or Full in the preferences panel. You can override the widths for each option:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Option</th><th style="text-align:left;">Selector</th><th style="text-align:left;">Default value</th></tr></thead><tbody><tr><td style="text-align:left;">Standard</td><td style="text-align:left;"><code>:root.citizen-feature-custom-width-clientpref-standard</code></td><td style="text-align:left;"><code>1080px</code></td></tr><tr><td style="text-align:left;">Wide</td><td style="text-align:left;"><code>:root.citizen-feature-custom-width-clientpref-wide</code></td><td style="text-align:left;"><code>1600px</code></td></tr><tr><td style="text-align:left;">Full</td><td style="text-align:left;"><code>:root.citizen-feature-custom-width-clientpref-full</code></td><td style="text-align:left;"><code>100vw</code></td></tr></tbody></table><h2 id="theme-modes" tabindex="-1">Theme modes <a class="header-anchor" href="#theme-modes" aria-label="Permalink to “Theme modes”">​</a></h2><p>Citizen supports Light, Dark, Pure Black, and Automatic modes. Use these selectors in <code>MediaWiki:Citizen.css</code> to apply mode-specific styles:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Mode</th><th style="text-align:left;">Selector</th></tr></thead><tbody><tr><td style="text-align:left;">Light</td><td style="text-align:left;"><code>.skin-theme-clientpref-day</code></td></tr><tr><td style="text-align:left;">Dark</td><td style="text-align:left;"><code>.skin-theme-clientpref-night</code></td></tr><tr><td style="text-align:left;">Pure black</td><td style="text-align:left;"><code>.skin-theme-clientpref-night.citizen-feature-pure-black-clientpref-1</code></td></tr><tr><td style="text-align:left;">Automatic</td><td style="text-align:left;"><code>.skin-theme-clientpref-os</code></td></tr></tbody></table><h3 id="inverting-images-in-dark-mode" tabindex="-1">Inverting images in dark mode <a class="header-anchor" href="#inverting-images-in-dark-mode" aria-label="Permalink to “Inverting images in dark mode”">​</a></h3><p>Some images, especially black text or icons on a transparent background, become invisible in dark mode. Citizen exposes a <code>--filter-invert</code> CSS variable that inverts colors only when a dark theme is active. Apply it to the element containing the image:</p><div class="language-css"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">filter</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: var( --filter-invert );</span></span></code></pre></div>`,33))])}const u=i(c,[["render",h]]);export{b as __pageData,u as default};
